 235→function normalizeToolName(name: string): string {
 236→  return name
 237→    .trim()
 238→    .replace(/^mcp__mittwald__/, '')
 239→    .replace(/^mittwald_mittwald_/, 'mittwald_')
 240→    .replace(/^mcp__/, '');
 241→}
