 247→function parseCsv(value: string): string[] {
 248→  return value
 249→    .split(',')
 250→    .map((x) => x.trim())
 251→    .filter(Boolean);
 252→}
 253→
 254→function parseIntArg(value: string, key: string): number {
 255→  const parsed = Number.parseInt(value, 10);
 256→  if (Number.isNaN(parsed) || parsed < 0) {
 257→    throw new Error(`Invalid ${key}: ${value}`);
 258→  }
 259→  return parsed;
 260→}
 261→
 262→function parseFloatArg(value: string, key: string): number {
 263→  const parsed = Number.parseFloat(value);
 264→  if (Number.isNaN(parsed) || parsed < 0 || parsed > 100) {
 265→    throw new Error(`Invalid ${key}: ${value}`);
 266→  }
 267→  return parsed;
 268→}
