 448→function loadPromptCases(
 449→  options: RunnerOptions
 450→): { cases: PromptCase[]; invalidFiles: InvalidPromptFile[] } {
 451→  if (!fs.existsSync(options.promptDir)) {
 452→    throw new Error(`Prompt directory not found: ${options.promptDir}`);
 453→  }
 454→
 455→  const files = walkJsonFiles(options.promptDir).filter(
 456→    (filePath) => path.basename(filePath) !== 'generation-manifest.json'
 457→  );
 458→
 459→  const invalidFiles: InvalidPromptFile[] = [];
 460→  const cases: PromptCase[] = [];
 461→
 462→  for (const filePath of files) {
 463→    let parsed: any;
 464→    try {
 465→      parsed = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
 466→    } catch (error) {
 467→      invalidFiles.push({
 468→        filePath,
 469→        error: error instanceof Error ? error.message : String(error),
 470→      });
 471→      continue;
 472→    }
 473→
 474→    const prompt = parsed?.input?.prompt;
 475→    const toolName = parsed?.input?.tool_name;
 476→    if (typeof prompt !== 'string' || typeof toolName !== 'string') {
 477→      continue;
 478→    }
 479→
 480→    const domain =
 481→      typeof parsed?.metadata?.domain === 'string'
 482→        ? parsed.metadata.domain
 483→        : path.basename(path.dirname(filePath));
 484→
 485→    if (options.domains && !options.domains.has(domain)) {
 486→      continue;
 487→    }
 488→
 489→    if (options.tools && !options.tools.has(normalizeToolName(toolName))) {
 490→      continue;
 491→    }
 492→
 493→    const fileBase = path.basename(filePath, '.json');
 494→    const displayName =
 495→      typeof parsed?.input?.display_name === 'string'
 496→        ? parsed.input.display_name
 497→        : fileBase;
 498→
 499→    cases.push({
 500→      id: fileBase,
 501→      domain,
 502→      promptFile: filePath,
 503→      toolName,
 504→      displayName,
 505→      prompt,
 506→    });
 507→  }
 508→
 509→  if (options.maxTools !== undefined) {
 510→    return {
 511→      cases: cases.slice(0, options.maxTools),
 512→      invalidFiles,
 513→    };
 514→  }
 515→
 516→  return { cases, invalidFiles };
 517→}
