 519→function createLineParser(onLine: (line: string) => void): {
 520→  push: (chunk: string) => void;
 521→  flush: () => void;
 522→} {
 523→  let buffer = '';
 524→
 525→  return {
 526→    push(chunk: string) {
 527→      buffer += chunk;
 528→      const lines = buffer.split(/\r?\n/);
 529→      buffer = lines.pop() ?? '';
 530→      for (const line of lines) {
 531→        if (line.length > 0) {
 532→          onLine(line);
 533→        }
 534→      }
 535→    },
 536→    flush() {
 537→      if (buffer.length > 0) {
 538→        onLine(buffer);
 539→      }
 540→      buffer = '';
 541→    },
 542→  };
 543→}
