 545→function parseClaudeEvent(
 546→  parsed: any,
 547→  toolsCalled: string[],
 548→  messages: string[],
 549→  toolCallErrors: string[],
 550→  mcpServerStatus: Record<string, string>
 551→): void {
 552→  if (parsed?.type === 'system' && parsed?.subtype === 'init') {
 553→    if (Array.isArray(parsed?.mcp_servers)) {
 554→      for (const server of parsed.mcp_servers) {
 555→        if (
 556→          typeof server?.name === 'string' &&
 557→          typeof server?.status === 'string'
 558→        ) {
 559→          mcpServerStatus[server.name] = server.status;
 560→        }
 561→      }
 562→    }
 563→    return;
 564→  }
 565→
 566→  if (parsed?.type === 'assistant' && parsed?.message?.content) {
 567→    const content = parsed.message.content;
 568→    if (Array.isArray(content)) {
 569→      for (const item of content) {
 570→        if (item?.type === 'tool_use' && typeof item?.name === 'string') {
 571→          toolsCalled.push(item.name);
 572→        }
 573→        if (item?.type === 'text' && typeof item?.text === 'string') {
 574→          messages.push(item.text);
 575→        }
 576→      }
 577→    }
 578→    return;
 579→  }
 580→
 581→  if (parsed?.type === 'result' && parsed?.is_error === true) {
 582→    toolCallErrors.push(
 583→      typeof parsed?.result === 'string'
 584→        ? parsed.result
 585→        : JSON.stringify(parsed?.result ?? parsed)
 586→    );
 587→  }
 588→}
 589→
 590→function parseCodexEvent(
 591→  parsed: any,
 592→  toolsCalled: string[],
 593→  messages: string[],
 594→  toolCallErrors: string[]
 595→): void {
 596→  if (parsed?.type === 'item.started' || parsed?.type === 'item.completed') {
 597→    const item = parsed?.item;
 598→    if (!item || typeof item !== 'object') {
 599→      return;
 600→    }
 601→
 602→    if (item.type === 'mcp_tool_call') {
 603→      if (typeof item.tool === 'string') {
 604→        toolsCalled.push(item.tool);
 605→      }
 606→      if (item.error) {
 607→        toolCallErrors.push(
 608→          typeof item.error === 'string' ? item.error : JSON.stringify(item.error)
 609→        );
 610→      }
 611→      if (item.status === 'failed') {
 612→        toolCallErrors.push(
 613→          `MCP tool call failed: ${typeof item.tool === 'string' ? item.tool : 'unknown_tool'}`
 614→        );
 615→      }
 616→      return;
 617→    }
 618→
 619→    if (item.type === 'agent_message' && typeof item.text === 'string') {
 620→      messages.push(item.text);
 621→      return;
 622→    }
 623→  }
 624→
 625→  if (parsed?.type === 'error') {
 626→    toolCallErrors.push(
 627→      typeof parsed?.message === 'string'
 628→        ? parsed.message
 629→        : JSON.stringify(parsed)
 630→    );
 631→  }
 632→}
 633→
 634→function parseOpencodeEvent(
 635→  parsed: any,
 636→  toolsCalled: string[],
 637→  messages: string[],
 638→  toolCallErrors: string[]
 639→): void {
 640→  if (parsed?.type === 'tool_use' && parsed?.part?.type === 'tool') {
 641→    if (typeof parsed?.part?.tool === 'string') {
 642→      toolsCalled.push(parsed.part.tool);
 643→    }
 644→    const status = parsed?.part?.state?.status;
 645→    if (status === 'error' || status === 'failed') {
 646→      toolCallErrors.push(
 647→        `Tool ${String(parsed?.part?.tool ?? 'unknown')} failed in opencode`
 648→      );
 649→    }
 650→    return;
 651→  }
 652→
 653→  if (parsed?.type === 'text' && typeof parsed?.part?.text === 'string') {
 654→    messages.push(parsed.part.text);
 655→    return;
 656→  }
 657→
 658→  if (parsed?.type === 'error') {
 659→    toolCallErrors.push(
 660→      typeof parsed?.error?.message === 'string'
 661→        ? parsed.error.message
 662→        : JSON.stringify(parsed?.error ?? parsed)
 663→    );
 664→  }
 665→}
