 912→async function listProjectsViaMw(): Promise<MittwaldProject[]> {
 913→  const result = await runCommandCapture('mw', ['project', 'list', '-o', 'json']);
 914→  if (result.timedOut) {
 915→    throw new Error('mw project list timed out');
 916→  }
 917→  if (result.exitCode !== 0) {
 918→    throw new Error(
 919→      `mw project list failed with code ${result.exitCode}: ${result.stderr || result.stdout}`
 920→    );
 921→  }
 922→
 923→  const parsed = parseJsonArrayFromOutput(result.stdout);
 924→  return parsed
 925→    .filter((item) => item && typeof item === 'object')
 926→    .map((item) => {
 927→      const project = item as Record<string, unknown>;
 928→      return {
 929→        id: typeof project.id === 'string' ? project.id : '',
 930→        shortId:
 931→          typeof project.shortId === 'string' ? project.shortId : undefined,
 932→        description:
 933→          typeof project.description === 'string'
 934→            ? project.description
 935→            : undefined,
 936→      };
 937→    })
 938→    .filter((item) => item.id.length > 0);
 939→}
