 941→async function cleanupProjectsByPrefix(
 942→  prefix: string
 943→): Promise<ProjectCleanupResult> {
 944→  const startedAt = new Date().toISOString();
 945→  const result: ProjectCleanupResult = {
 946→    enabled: true,
 947→    prefix,
 948→    startedAt,
 949→    finishedAt: startedAt,
 950→    matchedCount: 0,
 951→    deleted: [],
 952→    failed: [],
 953→  };
 954→
 955→  let projects: MittwaldProject[];
 956→  try {
 957→    projects = await listProjectsViaMw();
 958→  } catch (error) {
 959→    result.finishedAt = new Date().toISOString();
 960→    result.listError = error instanceof Error ? error.message : String(error);
 961→    return result;
 962→  }
 963→
 964→  const matches = projects.filter((project) =>
 965→    (project.description ?? '').startsWith(prefix)
 966→  );
 967→  result.matchedCount = matches.length;
 968→
 969→  for (const project of matches) {
 970→    const deletion = await runCommandCapture('mw', [
 971→      'project',
 972→      'delete',
 973→      project.id,
 974→      '--force',
 975→      '--quiet',
 976→    ]);
 977→
 978→    if (deletion.timedOut) {
 979→      result.failed.push({
 980→        id: project.id,
 981→        reason: 'mw project delete timed out',
 982→      });
 983→      continue;
 984→    }
 985→
 986→    if (deletion.exitCode !== 0) {
 987→      result.failed.push({
 988→        id: project.id,
 989→        reason: (deletion.stderr || deletion.stdout || `exit ${deletion.exitCode}`).trim(),
 990→      });
 991→      continue;
 992→    }
 993→
 994→    result.deleted.push(project.id);
 995→  }
 996→
 997→  result.finishedAt = new Date().toISOString();
 998→  return result;
 999→}
