1013→function extractSelfAssessment(rawText: string): AssessmentParseResult {
1014→  const startIndex = rawText.indexOf(SELF_ASSESSMENT_START);
1015→  const endIndex = rawText.indexOf(SELF_ASSESSMENT_END);
1016→
1017→  if (startIndex < 0 || endIndex < 0 || endIndex <= startIndex) {
1018→    return { error: 'Self-assessment markers not found' };
1019→  }
1020→
1021→  let payload = rawText
1022→    .slice(startIndex + SELF_ASSESSMENT_START.length, endIndex)
1023→    .trim();
1024→
1025→  if (payload.startsWith('```json')) {
1026→    payload = payload.replace(/^```json\s*/i, '').replace(/\s*```$/, '');
1027→  } else if (payload.startsWith('```')) {
1028→    payload = payload.replace(/^```\s*/, '').replace(/\s*```$/, '');
1029→  }
1030→
1031→  try {
1032→    const parsed = JSON.parse(payload) as SelfAssessment;
1033→    if (typeof parsed.success !== 'boolean') {
1034→      return { error: 'Self-assessment JSON missing boolean success field', rawJson: payload };
1035→    }
1036→    return { assessment: parsed, rawJson: payload };
1037→  } catch (error) {
1038→    return {
1039→      error: `Failed to parse self-assessment JSON: ${
1040→        error instanceof Error ? error.message : String(error)
1041→      }`,
1042→      rawJson: payload,
1043→    };
1044→  }
1045→}
