1171→function isAuthRelatedError(text: string): boolean {
1172→  const normalized = text.toLowerCase();
1173→  return (
1174→    normalized.includes('needs-auth') ||
1175→    normalized.includes('invalid_grant') ||
1176→    normalized.includes('no mittwald access token') ||
1177→    normalized.includes('unauthorized') ||
1178→    normalized.includes('authentication') ||
1179→    normalized.includes('oauth')
1180→  );
1181→}
