1183→function preflightRemediation(agent: AgentName, options: RunnerOptions): string {
1184→  if (agent === 'claude') {
1185→    return `Run 'claude' and authenticate the mittwald MCP server via '/mcp', or update ${options.mcpConfigPath} to a valid authenticated server.`;
1186→  }
1187→  if (agent === 'codex') {
1188→    return `Ensure server '${options.codexMcpServerName}' exists (codex mcp add ${options.codexMcpServerName} --url ${options.mcpUrl}) and authenticate with 'codex mcp login ${options.codexMcpServerName}'.`;
1189→  }
1190→  return "Configure and authenticate mittwald in opencode ('opencode mcp add' then 'opencode mcp auth mittwald').";
1191→}
1192→
1193→async function preflightAgent(
1194→  agent: AgentName,
1195→  options: RunnerOptions
1196→): Promise<AgentPreflightResult> {
1197→  const execution = await executePromptWithAgent(agent, PROBE_PROMPT, {
1198→    ...options,
1199→    timeoutMs: Math.min(options.timeoutMs, 90000),
1200→  });
1201→
1202→  const expectedToolCalled = execution.toolsCalled
1203→    .map((tool) => normalizeToolName(tool))
1204→    .includes(normalizeToolName(PROBE_TOOL_NAME));
1205→
1206→  const hasToolCallErrors = execution.toolCallErrors.length > 0;
1207→  const claudeNeedsAuth =
1208→    agent === 'claude' &&
1209→    Object.values(execution.mcpServerStatus).some((status) => status === 'needs-auth');
1210→
1211→  const authHint = isAuthRelatedError(
1212→    `${execution.stderr}\n${execution.stdout}\n${execution.messages.join('\n')}`
1213→  );
1214→
1215→  const ok =
1216→    execution.exitCode === 0 &&
1217→    !execution.timedOut &&
1218→    expectedToolCalled &&
1219→    !hasToolCallErrors &&
1220→    !claudeNeedsAuth &&
1221→    !authHint;
1222→
1223→  let reason: string | undefined;
1224→  if (!ok) {
1225→    if (execution.timedOut) {
1226→      reason = 'Probe timed out';
1227→    } else if (execution.exitCode !== 0) {
1228→      reason = `Probe exited with code ${execution.exitCode}`;
1229→    } else if (claudeNeedsAuth) {
1230→      reason = 'Claude reports MCP server needs OAuth authentication';
1231→    } else if (!expectedToolCalled) {
1232→      reason = `Probe did not call expected tool ${PROBE_TOOL_NAME}`;
1233→    } else if (hasToolCallErrors) {
1234→      reason = `Probe had MCP tool errors: ${execution.toolCallErrors.join('; ')}`;
1235→    } else if (authHint) {
1236→      reason = 'Probe output indicates OAuth/authentication issue';
1237→    } else {
1238→      reason = 'Probe failed for unknown reason';
1239→    }
1240→    reason = `${reason} Remediation: ${preflightRemediation(agent, options)}`;
1241→  }
1242→
1243→  return {
1244→    agent,
1245→    ok,
1246→    reason,
1247→    details: {
1248→      commandAvailable: execution.exitCode !== 127,
1249→      expectedToolCalled,
1250→      hasToolCallErrors,
1251→      claudeNeedsAuth,
1252→      probeExitCode: execution.exitCode,
1253→      probeTimedOut: execution.timedOut,
1254→    },
1255→    execution,
1256→  };
1257→}
