1408→function generateMarkdownSummary(summary: RunSummary): string {
1409→  const lines: string[] = [];
1410→  lines.push(`# Agent E2E Summary: ${summary.runId}`);
1411→  lines.push('');
1412→  lines.push(`- Generated: ${summary.generatedAt}`);
1413→  lines.push(`- Coverage mode: ${summary.gate.mode}`);
1414→  lines.push(`- Required coverage: ${summary.gate.requiredCoverage}%`);
1415→  lines.push(`- Gate: ${summary.gate.passed ? 'PASS' : 'FAIL'}`);
1416→  lines.push(`- Cleanup test projects: ${summary.options.cleanupTestProjects ? 'enabled' : 'disabled'}`);
1417→  lines.push(`- Cleanup project prefix: ${summary.options.cleanupProjectPrefix}`);
1418→  lines.push('');
1419→
1420→  lines.push('## Counts');
1421→  lines.push('');
1422→  lines.push(`- Total tools: ${summary.counts.totalTools}`);
1423→  lines.push(`- Covered tools: ${summary.counts.coveredTools}`);
1424→  lines.push(`- Tool coverage: ${summary.counts.toolCoveragePercent}%`);
1425→  lines.push(`- Case runs: ${summary.counts.totalCaseRuns}`);
1426→  lines.push(`- Passed runs: ${summary.counts.passedCaseRuns}`);
1427→  lines.push(`- Failed runs: ${summary.counts.failedCaseRuns}`);
1428→  lines.push(`- Matrix coverage: ${summary.counts.matrixCoveragePercent}%`);
1429→  lines.push('');
1430→
1431→  lines.push('## Per-Agent Coverage');
1432→  lines.push('');
1433→  lines.push('| Agent | Total | Passed | Failed | Coverage |');
1434→  lines.push('| --- | ---: | ---: | ---: | ---: |');
1435→  for (const agent of summary.options.agents) {
1436→    const stats = summary.perAgent[agent];
1437→    lines.push(
1438→      `| ${agent} | ${stats.total} | ${stats.passed} | ${stats.failed} | ${stats.coveragePercent}% |`
1439→    );
1440→  }
1441→  lines.push('');
1442→
1443→  if (summary.promptInventory.invalidFiles.length > 0) {
1444→    lines.push('## Malformed Prompt Files');
1445→    lines.push('');
1446→    for (const invalid of summary.promptInventory.invalidFiles) {
1447→      lines.push(`- ${invalid.filePath}: ${invalid.error}`);
1448→    }
1449→    lines.push('');
1450→  }
1451→
1452→  const preflightFailures = summary.preflight.filter((entry) => !entry.ok);
1453→  if (preflightFailures.length > 0) {
1454→    lines.push('## Preflight Failures');
1455→    lines.push('');
1456→    for (const failure of preflightFailures) {
1457→      lines.push(`- ${failure.agent}: ${failure.reason}`);
1458→    }
1459→    lines.push('');
1460→  }
1461→
1462→  const uncovered = summary.perTool.filter((tool) => !tool.covered);
1463→  if (uncovered.length > 0) {
1464→    lines.push('## Uncovered Tools');
1465→    lines.push('');
1466→    lines.push('| Tool | Domain | Status by Agent |');
1467→    lines.push('| --- | --- | --- |');
1468→    for (const tool of uncovered) {
1469→      const status = summary.options.agents
1470→        .map((agent) => `${agent}:${tool.byAgent[agent]}`)
1471→        .join(', ');
1472→      lines.push(`| ${tool.toolName} | ${tool.domain} | ${status} |`);
1473→    }
1474→    lines.push('');
1475→  }
1476→
1477→  if (summary.cleanup) {
1478→    lines.push('## Project Cleanup');
1479→    lines.push('');
1480→    lines.push(`- Prefix: ${summary.cleanup.prefix}`);
1481→    lines.push(`- Matched projects: ${summary.cleanup.matchedCount}`);
1482→    lines.push(`- Deleted projects: ${summary.cleanup.deleted.length}`);
1483→    lines.push(`- Failed deletions: ${summary.cleanup.failed.length}`);
1484→    if (summary.cleanup.listError) {
1485→      lines.push(`- List error: ${summary.cleanup.listError}`);
1486→    }
1487→    if (summary.cleanup.deleted.length > 0) {
1488→      lines.push(`- Deleted IDs: ${summary.cleanup.deleted.join(', ')}`);
1489→    }
1490→    if (summary.cleanup.failed.length > 0) {
1491→      lines.push(
1492→        `- Failed IDs: ${summary.cleanup.failed
1493→          .map((item) => `${item.id} (${item.reason})`)
1494→          .join(', ')}`
1495→      );
1496→    }
1497→    lines.push('');
1498→  }
1499→
1500→  if (summary.gate.reasons.length > 0) {
1501→    lines.push('## Gate Failure Reasons');
1502→    lines.push('');
1503→    for (const reason of summary.gate.reasons) {
1504→      lines.push(`- ${reason}`);
1505→    }
1506→    lines.push('');
1507→  }
1508→
1509→  return lines.join('\n');
1510→}
1511→
1512→function printUsage(): void {
1513→  console.log(
1514→    [
1515→      'Usage: tsx evals/scripts/agent-e2e-runner.ts [options]',
1516→      '',
1517→      'Options:',
1518→      '  --agents=claude,codex,opencode   Comma-separated agents (default: claude)',
1519→      '  --prompt-dir=evals/prompts        Prompt directory root',
1520→      '  --output-dir=evals/results/agent-e2e',
1521→      `  --timeout-ms=${DEFAULT_TIMEOUT_MS}              Timeout per prompt`,
1522→      '  --mcp-config=.mcp.json            Claude MCP config file',
1523→      '  --target=fly|mittwald             Target endpoint selection (default: fly)',
1524→      '  --mcp-url=https://mittwald-mcp-fly2.fly.dev/mcp',
1525→      '  --domains=apps,databases          Restrict domains',
1526→      '  --tools=mcp__mittwald__foo,...    Restrict tools',
1527→      '  --max-tools=10                    Run only first N cases',
1528→      '  --skip-preflight                  Skip readiness probe',
1529→      '  --preflight-only                  Run probes only',
1530→      '  --fail-fast                       Stop on first failed case',
1531→      '  --require-coverage=100            Coverage gate threshold',
1532→      '  --coverage-mode=all-agents|any-agent',
1533→      '  --require-self-assessment         Fail if self-assessment is missing/invalid',
1534→      '  --cleanup-test-projects           Enable project cleanup (default: enabled)',
1535→      '  --no-cleanup-test-projects        Disable project cleanup',
1536→      '  --cleanup-project-prefix=<prefix> Prefix for project tagging/cleanup (default: run ID)',
1537→      '  --codex-mcp-server-name=mittwald  Codex server config name',
1538→      '  --claude-model=<name>',
1539→      '  --codex-model=<name>',
1540→      '  --opencode-model=<provider/model>',
1541→    ].join('\n')
1542→  );
1543→}
1544→
1545→async function main(): Promise<void> {
1546→  let options: RunnerOptions;
1547→  try {
1548→    options = parseArgs(process.argv.slice(2));
1549→  } catch (error) {
1550→    console.error(
1551→      `Argument error: ${error instanceof Error ? error.message : String(error)}`
1552→    );
1553→    printUsage();
1554→    process.exit(1);
1555→    return;
1556→  }
1557→
1558→  const runId = `agent-e2e-${new Date()
1559→    .toISOString()
1560→    .replace(/[:.]/g, '-')
1561→    .slice(0, 19)}`;
1562→  const cleanupProjectPrefix = options.cleanupProjectPrefix ?? runId;
1563→  const runDir = path.join(options.outputDir, runId);
1564→  ensureDir(runDir);
1565→
1566→  if (options.preflightOnly) {
1567→    options.requireCoverage = 0;
1568→  }
1569→
1570→  console.log(`\n[agent-e2e] Run ID: ${runId}`);
1571→  console.log(`[agent-e2e] Agents: ${options.agents.join(', ')}`);
1572→  console.log(`[agent-e2e] Prompt dir: ${options.promptDir}`);
1573→  console.log(`[agent-e2e] Target: ${options.target}`);
1574→  console.log(`[agent-e2e] MCP URL: ${options.mcpUrl}`);
1575→  console.log(
1576→    `[agent-e2e] Cleanup: ${options.cleanupTestProjects ? 'enabled' : 'disabled'} (prefix: ${cleanupProjectPrefix})`
1577→  );
1578→  console.log(`[agent-e2e] Output: ${runDir}`);
1579→
1580→  const { cases: promptCases, invalidFiles } = loadPromptCases(options);
1581→  console.log(
1582→    `[agent-e2e] Loaded ${promptCases.length} prompt case(s), ${invalidFiles.length} malformed file(s)`
1583→  );
1584→
1585→  const preflight: AgentPreflightResult[] = [];
1586→  if (!options.skipPreflight) {
1587→    console.log('\n[agent-e2e] Running preflight probes...');
1588→    for (const agent of options.agents) {
1589→      const result = await preflightAgent(agent, options);
1590→      preflight.push(result);
1591→      console.log(
1592→        `[agent-e2e] Preflight ${agent}: ${result.ok ? 'OK' : 'FAILED'}${
1593→          result.reason ? ` (${result.reason})` : ''
1594→        }`
1595→      );
1596→    }
1597→  }
1598→
1599→  const shouldAbortForPreflight =
1600→    !options.skipPreflight && preflight.some((result) => !result.ok);
1601→  const results: ToolCaseResult[] = [];
1602→
1603→  if (!options.preflightOnly && !shouldAbortForPreflight && invalidFiles.length === 0) {
1604→    for (const agent of options.agents) {
1605→      console.log(`\n[agent-e2e] Executing prompt set with ${agent}...`);
1606→      for (let index = 0; index < promptCases.length; index++) {
1607→        const promptCase = promptCases[index];
1608→        console.log(
1609→          `[agent-e2e] [${agent}] ${index + 1}/${promptCases.length} ${promptCase.displayName}`
1610→        );
1611→
1612→        const runPrompt = withRunCleanupGuardrails(
1613→          promptCase.prompt,
1614→          cleanupProjectPrefix
1615→        );
1616→        const startedAt = new Date().toISOString();
1617→        const execution = await executePromptWithAgent(agent, runPrompt, options);
1618→        const finishedAt = new Date().toISOString();
1619→        const evaluation = evaluateCase(promptCase, execution, options);
1620→
1621→        const rawDir = path.join(
1622→          runDir,
1623→          'raw',
1624→          agent,
1625→          sanitizeFilePart(promptCase.domain)
1626→        );
1627→        ensureDir(rawDir);
1628→
1629→        const caseStem = sanitizeFilePart(promptCase.id);
1630→        const rawOutputFile = path.join(rawDir, `${caseStem}.stdout.jsonl`);
1631→        const stdoutFile = path.join(rawDir, `${caseStem}.stdout.txt`);
1632→        const stderrFile = path.join(rawDir, `${caseStem}.stderr.txt`);
1633→        writeText(rawOutputFile, execution.stdout);
1634→        writeText(stdoutFile, execution.messages.join('\n'));
1635→        writeText(stderrFile, execution.stderr);
1636→
1637→        const caseResult: ToolCaseResult = {
1638→          runId,
1639→          agent,
1640→          promptCaseId: promptCase.id,
1641→          domain: promptCase.domain,
1642→          promptFile: promptCase.promptFile,
1643→          toolName: promptCase.toolName,
1644→          displayName: promptCase.displayName,
1645→          startedAt,
1646→          finishedAt,
1647→          durationMs: execution.durationMs,
1648→          status: evaluation.status,
1649→          failureCategory: evaluation.failureCategory,
1650→          failureReason: evaluation.failureReason,
1651→          expectedToolCalled: evaluation.expectedToolCalled,
1652→          toolsCalled: execution.toolsCalled,
1653→          toolCallErrors: execution.toolCallErrors,
1654→          selfAssessment: evaluation.selfAssessment,
1655→          rawOutputFile,
1656→          stdoutFile,
1657→          stderrFile,
1658→        };
1659→
1660→        const resultFile = path.join(
1661→          runDir,
1662→          'results',
1663→          agent,
1664→          sanitizeFilePart(promptCase.domain),
1665→          `${caseStem}.json`
1666→        );
1667→        writeJson(resultFile, caseResult);
1668→        results.push(caseResult);
1669→
1670→        if (caseResult.status === 'failure') {
1671→          console.log(
1672→            `[agent-e2e] [${agent}] FAILED: ${promptCase.displayName} (${caseResult.failureCategory})`
1673→          );
1674→          if (!options.continueOnFailure) {
1675→            console.log('[agent-e2e] fail-fast enabled, stopping execution');
1676→            break;
1677→          }
1678→        } else {
1679→          console.log(`[agent-e2e] [${agent}] PASSED: ${promptCase.displayName}`);
1680→        }
1681→      }
1682→    }
1683→  } else if (invalidFiles.length > 0) {
1684→    console.log(
1685→      '\n[agent-e2e] Skipping execution because malformed prompt files were detected.'
1686→    );
1687→  } else if (shouldAbortForPreflight) {
1688→    console.log('\n[agent-e2e] Skipping execution due to preflight failures.');
1689→  }
1690→
1691→  let cleanupResult: ProjectCleanupResult | undefined;
1692→  if (!options.preflightOnly && options.cleanupTestProjects) {
1693→    console.log(
1694→      `\n[agent-e2e] Cleaning up test projects with prefix '${cleanupProjectPrefix}'...`
1695→    );
1696→    cleanupResult = await cleanupProjectsByPrefix(cleanupProjectPrefix);
1697→    writeJson(path.join(runDir, 'project-cleanup.json'), cleanupResult);
1698→
1699→    if (cleanupResult.listError) {
1700→      console.log(`[agent-e2e] Cleanup list error: ${cleanupResult.listError}`);
1701→    } else {
1702→      console.log(
1703→        `[agent-e2e] Cleanup matched ${cleanupResult.matchedCount} project(s), deleted ${cleanupResult.deleted.length}, failed ${cleanupResult.failed.length}`
1704→      );
1705→      if (cleanupResult.deleted.length > 0) {
1706→        console.log(
1707→          `[agent-e2e] Cleanup deleted IDs: ${cleanupResult.deleted.join(', ')}`
1708→        );
1709→      }
1710→      if (cleanupResult.failed.length > 0) {
1711→        console.log(
1712→          `[agent-e2e] Cleanup failed IDs: ${cleanupResult.failed
1713→            .map((item) => `${item.id} (${item.reason})`)
1714→            .join(', ')}`
1715→        );
1716→      }
1717→    }
1718→  }
1719→
1720→  const summary = generateSummary(
1721→    runId,
1722→    runDir,
1723→    options,
1724→    cleanupProjectPrefix,
1725→    promptCases,
1726→    invalidFiles,
1727→    preflight,
1728→    results,
1729→    cleanupResult
1730→  );
1731→
1732→  const summaryJsonFile = path.join(runDir, 'summary.json');
1733→  const summaryMdFile = path.join(runDir, 'summary.md');
1734→  writeJson(summaryJsonFile, summary);
1735→  writeText(summaryMdFile, generateMarkdownSummary(summary));
1736→
1737→  console.log('\n[agent-e2e] Summary');
1738→  console.log(`[agent-e2e] Tool coverage: ${summary.counts.toolCoveragePercent}%`);
1739→  console.log(`[agent-e2e] Matrix coverage: ${summary.counts.matrixCoveragePercent}%`);
1740→  console.log(`[agent-e2e] Gate: ${summary.gate.passed ? 'PASS' : 'FAIL'}`);
1741→  console.log(`[agent-e2e] JSON: ${summaryJsonFile}`);
1742→  console.log(`[agent-e2e] Markdown: ${summaryMdFile}`);
1743→
1744→  if (!summary.gate.passed) {
1745→    for (const reason of summary.gate.reasons) {
1746→      console.log(`[agent-e2e] Gate reason: ${reason}`);
1747→    }
1748→    process.exit(1);
1749→    return;
1750→  }
1751→
1752→  process.exit(0);
1753→}
1754→
1755→if (import.meta.url === `file://${process.argv[1]}`) {
1756→  main().catch((error) => {
1757→    console.error('Fatal error in agent-e2e runner:', error);
1758→    process.exit(1);
1759→  });
1760→}
